global_settings.path_template:
{%- if out_dir != '' -%}
{{ out_dir }}
{%- else -%}
{{ download_dir }}
{%- endif -%}
{%- if user_name != '' and user_name != channel -%}
/{{ channel }}-{{ user_name }}
{%- else -%}
/{{ channel }}
{%- endif -%}
/{{ ctime | date: '%Y-%m-%d', 'local' }}
{%- if platform != 'unknown' -%}
/{{ platform }}-{{ channel }}
{%- else -%}
/{{ channel }}
{%- endif -%}
{%- if user_name != '' and user_name != channel -%}
-{{ user_name }}
{%- endif -%}
{%- if title != '' -%}
-{{ title | truncate: 40 }}
{%- endif -%}
-{{ ctime | date: '%Y-%m-%d-%H%M%S-%3f', 'local' }}.{{ format }}

global_settings.notify_title_template:
{%- case event -%}
  {%- when 'live_start', 'live_end' -%}
    [{{ platform }}]
    {{- ' ' -}}
    {%- if user_name != '' -%}
      {{ user_name }}
    {%- else -%}
      {{ channel }}
    {%- endif -%}
    {{- ' ' -}}
    {%- if event == 'live_start' -%}
      is live
    {%- else -%}
      is offline
    {%- endif -%}
    {%- if title != '' -%}
      : {{ title }}
    {%- endif -%}
  {%- when 'error' -%}
    something went wrong
{%- endcase -%}

global_settings.notify_body_template:
{%- assign scheme = service_url | split: '://' | first -%}

{%- case event -%}
  {%- when 'live_start', 'live_end' -%}
    {%- case scheme -%}
      {%- when 'mailto', 'mailtos' -%}
<p><span><b>URL</b>: </span><span><a href="{{ url }}" target="_blank">{{ url }}</a></span></p>
<p><span><b>Platform</b>: </span><span>{{ platform }}</span></p>
<p><span><b>Channel</b>: </span><span>{{ channel }}</span></p>
<p><span><b>User ID</b>: </span><span>{{ user_id }}</span></p>
<p><span><b>User Name</b>: </span><span>{{ user_name }}</span></p>
<p><span><b>Avatar</b>: </span><span><a href="{{ avatar }}" target="_blank">{{ avatar }}</a></span></p>
<p><span><b>Title</b>: </span><span>{{ title }}</span></p>
<p><span><b>Categories</b>: </span><span>{{ categories | join: ', ' }}</span></p>
<p><span><b>Live ID</b>: </span><span>{{ live_id }}</span></p>
<p><span><b>Start Time</b>: </span><span>{{ start_time }}</span></p>
<div><a href="{{ cover }}" target="_blank"><img src="{{ cover }}" alt="Cover"/></a></div>
      {%- when 'discord' -%}
**URL**: {{ url }}
**Platform**: {{ platform }}
**Channel**: {{ channel }}
**User ID**: {{ user_id }}
**User Name**: {{ user_name }}
**Avatar**: [{{ avatar }}]({{ avatar }})
**Title**: {{ title }}
**Categories**: {{ categories | join: ', ' }}
**Live ID**: {{ live_id }}
**Start Time**: {{ start_time }}
![Cover]({{ cover }})
      {%- else -%}
URL: {{ url }}
Platform: {{ platform }}
Channel: {{ channel }}
User ID: {{ user_id }}
User Name: {{ user_name }}
Avatar: {{ avatar }}
Title: {{ title }}
Categories: {{ categories | join: ', ' }}
Live ID: {{ live_id }}
Start Time: {{ start_time }}
Cover: {{ cover }}
    {%- endcase -%}
  {%- when 'error' -%}
    {%- case scheme -%}
      {%- when 'mailto', 'mailtos' -%}
<pre style="color: red; font-weight: 800;">
{{ error }}
</pre>
      {%- when 'discord' -%}
```
{{ error }}
```
      {%- else -%}
{{ error }}
    {%- endcase -%}
{%- endcase -%}
